// Pull both runs' ensures-derived equalities for the returned key into
// the proof context so the trigger gap between r1 and r2 is closed.
assert(r1 == pre_self_@.index(i as int));
assert(r2 == pre_self_@.index(i as int));
assert(r1 == r2);

// Do the same for the resulting view: both posts agree with
